```class Solution {
public:
    int minChanges(vector<int>& nums, int k) {
        int n = nums.size();
        vector<int> dp(n + 1, 0);
        for (int i = 1; i <= n; i++) {
            dp[i] = dp[i - 1] + (nums[i - 1] % 2);
        }
        int res = n;
        for (int i = k; i <= n; i++) {
            res = min(res, i - dp[i] + dp[i - k]);
        }
        return res;
    }
};```
